var 木里得斯='https://fqnovels.indevs.in';

function 密钥 () {
    const {java, source, book} = this;
    let loginInfoMap = source.getLoginInfoMap();
    let apikey = "";
    if (loginInfoMap && loginInfoMap['密钥'] && loginInfoMap['密钥'] !== "") {
        apikey = loginInfoMap['密钥'];
    }

    return apikey;
}



function getNovelComment(book_id, type) {
    const { java, source, book } = this
    if (type == 0) {
    let count = book.getVariable("custom")
    if (count && count == "") count = 5
    let res = java.ajax(`https://changdunovel.com/reading/ugc/novel_comment/book/v1?query_type=0&offset=0&count=${count}&sort=create_time&need_hot_comment=0&book_id=${book_id}&aid=1967&addQueryPrefix=true`) 
    let rs = JSON.parse(res)
    if (rs.code == "101003") return "";
    let comments = rs.data.comment;
    let result = `\n📄 书评：${comments.length>0?("(共 "+ comments.length +" 条)"):""}\n`
    comments.forEach(c => {
        let startNum = 5 - parseInt(c.score/2)
        let text = c.text.replace(/\#/g, "--")
        result += `${c.user_info.gender==1?"👨🏻":"👱🏻"} ${c.user_info.user_name} || ${"★★★★★★☆☆☆☆☆".slice(startNum, startNum + 5)}\n${text}\n&lrm;\n`
    })
    return result
    } 
  let result = ""
  return result
}

