const tags = "题材&全部$$热血$6$$冒险$7$$科幻$8$$霸总$9$$玄幻$10$$校园$11$$修真$12$$搞笑$13$$穿越$14$$后宫$15$$耽美$16$$恋爱$17$$悬疑$18$$恐怖$19$$战争$20$$动作$21$$同人$22$$竞技$23$$励志$24$$架空$25$$灵异$26$$百合$27$$古风$28$$生活$29&&进度&连载$1$$完结$2&&受众&少年$1$$少女$2$$青年$3$$少儿$4"

const list = [];

const fl = {
  "题材": "tags",
  "进度": "finish",
  "受众": "list"
}

const url = "/index.php/api/data/comic?";
const type = {
  tags: undefined,
  order: "hits",
  list: 0,
  pay: 0,
  finish: 0
};

tags.split("&&").forEach(bigCat => {
  let [bigTitle, cat] = bigCat.split("&");
  list.push(item(bigTitle, null, 1));
  cat.split("$$").forEach(tag => {
    let [title, id] = tag.split("$");
    let typeKey = fl[bigTitle];
    let queryType = Object.assign({}, type, {[typeKey]:id})
    let query = Object.entries(queryType)
      .filter(([_, v]) => v !== undefined)
      .map(([k, v]) => `type[${k}]=${v}`)
      .join("&");

    list.push(item(title, url + query + "&page={{page}}"));
  });
});

JSON.stringify(list)

