let header1 = {
    "User-Agent": pc_ua,
    "Cookie": cookie1
};
let header = Object.assign({}, header1, {"User-Agent": ua3});
        let html1 = get1("https://d.pcs.baidu.com/rest/2.0/pcs/file?app_id=250528&method=locatedownload&path="+encodeURIComponent(path)+"&use=1", header,this);       
        let url = html1.urls[0].url;
        if (size < 52428800) {
            return {url: url, header: header1};
        } else {
            return {url: url, header: header};
        }
    }

