function getImgList(){
    var p = "chapterImages = \\[(.*?)\\]";
    var path = html.match(p)[1].replace(/\"/g, "").replace(/\//g,"").split(",");
    var piclist = new Array([path.length]);
    for (var i = 0; i < path.length; i++) {
        piclist[i] = "https://restp.dongqiniqin.com//" + path[i];
    }
    return piclist;
}@Header:{Referer:host}

