		 id = raws[n].id
		 let bookUrl = baseUrl.replace(/(serie-)\d+/,'$1'+id).replace(/(\?sid=)\d+/,'$1'+id)
		 result = java.ajax(bookUrl)
		 book.bookUrl = bookUrl
		 let data = JSON.parse(result).pageProps.serie
		 result = data
		}
	}
	else n = 0,java.toast('没有编号为'+x+'的源')
}
for(let i in raws){
	info += (raws[i].id==id?u:nu) + (i-0+1) + '：' + raws[i].slug + '\n'
}
result.info = info
result.raw_id = id
Packages.java.util.LinkedHashMap(result)

