function Login() {
	const result = JSON.parse(source.getLoginInfo());
	var username = result['账号'];
	var password = result['密码'];
	var options = {
		body: `username=${username}&password=${password}&submit_login=1`,
		method: 'POST'
	};
	if (Get('urls')[0] == 1) {
		login('请先获取URL');
