function login() {
  let loginInfo = source.getLoginInfoMap();
  let username = loginInfo.get("账号");
  let password = loginInfo.get("密码");

  try {
    java.toast("✅正在登录中...请稍候");


    let loginUrl = "https://www.ijjjjxsw.com/e/member/doaction.php";

    let body = `enews=login&username=${encodeURIComponent(username)}&password=${encodeURIComponent(password)}&lifetime=315360000`;

    let response = java.post(loginUrl, body, {
      "Content-Type": "application/x-www-form-urlencoded"
    });

    let respBody = response.body();
    java.log("登录响应: " + respBody);

    if (respBody.includes("登录成功") || respBody.includes("location.href") || respBody.includes("history.go") || respBody.includes("首页") || respBody.includes("window.location")) {
      java.log("success");
      let cookies = cookie.getCookie(loginUrl);
      let cookieHeader = JSON.stringify({ cookie: cookies });
      source.putLoginHeader(cookieHeader);
      java.toast("✅登录成功");
    } else if (respBody.includes("密码错误") || respBody.includes("用户名不存在") || respBody.includes("登录失败")) {
      java.log("❌登录失败: " + respBody);
      java.toast("❌登录失败，请检查账号密码");
    } else {

      java.log("可能登录成功，响应内容: " + respBody);
      let cookies = cookie.getCookie(loginUrl);
      if (cookies && cookies.length > 0) {
        let cookieHeader = JSON.stringify({ cookie: cookies });
        source.putLoginHeader(cookieHeader);
        java.toast("✅登录成功");
      } else {
        java.toast("❌登录状态异常");
      }
    }
  } catch (error) {
    java.log("❌登录失败: " + error.message);
    java.toast("❌登录失败: " + error.message);
  }
}

function clearLogin() {
  try {
    source.removeLoginHeader();
    java.toast('✅用户数据已清除[退出登录]');
  } catch (error) {
    java.toast(`❌清除失败：${error.message}`);
  }
}

