jsLib:
function getHost() {
    return "https://v1.vossc.com";
}

function deviceType() {
    let {
        java
    } = this;
    try {
        java.deviceID();
        return false;
    } catch (e) {
        try {
            java.androidId();
            return true;
        } catch (e) {
            return false;
        }
    }
}

function checkEnv() {
    let {
        java,
        source
    } = this;
    let isModified = false;
    try {
        new Packages.io.legato.kazusa.utils.TimeoutCancellationException('');
        isModified = true;
    } catch (e) {
        isModified = typeof source.loginUi == 'function' ? false : true;
    }

    try {
        java.put("is_modified_version", isModified ? "true" : "false");
    } catch (e) {}

    return isModified;
}

function isQRead() {
    let {
        java
    } = this;
    try {
        return java.qread && java.qread() == "1";
    } catch (e) {
        return false;
    }
}

function getServerHost() {
    let {
        source
    } = this;
    try {
        const config = JSON.parse(source.getVariable());
        return config?.[0]?.host || getHost.call(this);
    } catch (e) {
        return getHost.call(this);
    }
}

function getSessionId() {
    const {
        cookie,
        source
    } = this;
    try {
        let cookieHeader = String(cookie.getCookie('fanqienovel.com'));
        let sessionId = cookieHeader.match(/sessionid=([^;]+)/)?.[1] || null;
        if (sessionId) {
            return sessionId;
        }
    } catch (e) {}
    try {
        let loginInfo = source.getLoginInfoMap() || {};
        return loginInfo['番茄登录Token'] || "";
    } catch (e) {
        return "";
    }
}

function splitArray(input, size) {
    let output = []
    for (let i = 0; i < input.length; i += size) {
        output.push(input.slice(i, i + size))
    }
    return output
}

function getCommentIconColor() {
    let {
        source
    } = this;
    let color = "#666666";
    let loginInfo = source.getLoginInfoMap() || "";
    if (loginInfo['段评图标颜色'] && loginInfo['段评图标颜色'].startsWith('#')) {
        color = loginInfo['段评图标颜色'];
    }
    return color;
}

function wrapContentForIOS(content) {
    const pureContent = content.trim();
    if (deviceType.call(this)) {
        return pureContent;
    }
    let lines = pureContent.split('\n').map(line => {
        if (line.trim()) {
            const trimLine = line.trim().replace(/\s+/g, ' ');
            return `<div rs-native>${trimLine}</div>`;
        }
        return line;
    });
    return lines.join('\n');
}

function buildCommentUrl(sourceType, bid, cid, para) {
    let host = getServerHost.call(this);

    switch (sourceType) {
        case 'qm':
            return host + '/qm_comment?item_id=' + cid + '&book_id=' + bid + '&paragraph_id=' + para;
        case 'qq':
            return host + '/qq_comment?bid=' + bid + '&cid=' + cid + '&para=' + para;
        case 'fq':
        default:
            return host + '/idea_comment?item_id=' + cid + '&book_id=' + bid + '&para=' + para + '&sessionid=' + getSessionId.call(this);
    }
}

function getCommentSourceName(sourceType) {
    switch (sourceType) {
        case 'qm':
            return '七猫';
        case 'qq':
            return '企鹅';
        case 'fq':
        default:
            return '番茄';
    }
}

function startCommentBrowser(url, title) {
    let {
        java,
        source
    } = this;

    let userHeight = source.getLoginInfoMap().get("📐段评高度%");
    let heightPercentage = 0.75; // 默认
    if (userHeight) {
        let h = parseFloat(userHeight);
        if (!isNaN(h)) {
            if (h > 1) h = h / 100;
            heightPercentage = Math.min(1, Math.max(0, h));
        }
    }

    let userRadius = source.getLoginInfoMap().get("📐段评圆角，填0-50之间");
    let cornerRadius = 20; // 默认20
    if (userRadius) {
        let r = parseInt(userRadius);
        if (!isNaN(r)) {
            cornerRadius = Math.min(50, Math.max(0, r)); // 限制在0-50之间
        }
    }

    if (isQRead.call(this)) {
        java.startBrowserDp(url, title);
    } else {
        let isModifiedVersion = checkEnv.call(this);
        if (isModifiedVersion) {
            try {
                let htmlContent = java.ajax(url);
                java.showBrowser(
                    url,
                    htmlContent,
                    `window.java=java;`,
                    JSON.stringify({
                        "expandedCornersRadius": cornerRadius,
                        "dismissOnTouchOutside": true,
                        "isDraggable": true,
                        "shouldDimBackground": true,
                        "backgroundDimAmount": 0.5,
                        "hardwareAccelerated": true,
                        "isNestedScrollingEnabled": true,
                        "isGestureInsetBottomIgnored": true,
                        "setFitToContents": false,
                        "heightPercentage": heightPercentage,
                        "isHideable": true
                    })
                );
            } catch (e) {
                java.showBrowser(
                    url,
                    null,
                    `window.java=java;`,
                    JSON.stringify({
                        "expandedCornersRadius": cornerRadius,
                        "dismissOnTouchOutside": true,
                        "hardwareAccelerated": true,
                        "isNestedScrollingEnabled": true,
                        "isGestureInsetBottomIgnored": true,
                        "heightPercentage": heightPercentage,
                        "isHideable": true
                    })
                );
            }
        } else {
            java.startBrowser(url, title);
        }
    }
}

function createCommentHtmlTag(displayText, url, sourceName) {
    const encodedUrl = url.replace(/&/g, '&amp;');
    return '<comment count="' + displayText + '" onPress="java.' +
        (isQRead.call(this) ? 'startBrowserDp' : 'startBrowser') +
        '(\'' + encodedUrl + '\',\'' + sourceName + '段评\')" />';
}

function createSvg(number, color, bid, cid, para, sourceType = 'fq') {
    let { java, source, cache } = this;
    var displayText = number > 99 ? "99+" : number;
    var date = String(Date.now()).match(/(\d{6}$)/)[1];

    let isIOS = !deviceType.call(this);
    if (isIOS) {
        let commentUrl = buildCommentUrl.call(this, sourceType, bid, cid, para);
        let sourceName = getCommentSourceName(sourceType);
        return createCommentHtmlTag.call(this, displayText, commentUrl, sourceName);
    }

    let isQingRead = isQRead.call(this);
    let isModifiedVersion = checkEnv.call(this);

    let customSvgRaw = source.getLoginInfoMap().get("自定义气泡SVG");

    let customSvg = "";
    if (customSvgRaw) {
        if (typeof customSvgRaw == 'function') {
            try { customSvg = customSvgRaw(); } catch (e) {}
        } else if (typeof customSvgRaw == 'string') {
            customSvg = customSvgRaw;
        } else {
            customSvg = String(customSvgRaw);
        }
    }

    const isValidSvg = customSvg && customSvg.trim().startsWith('<svg') && customSvg.trim().endsWith('</svg>');

    let imageStyle = cache.get("imgstyle") ?? "TEXT";

    var svg;
    if (isQingRead || isModifiedVersion) {
        if (isValidSvg) {
            svg = customSvg.replace(/\{\{color\}\}/g, color).replace(/\{\{displayText\}\}/g, displayText);
        } else {
            svg = '<svg width="160" height="120" xmlns="http://www.w3.org/2000/svg"><path d="M 55 10 L 120 10 Q 150 10 150 40 L 150 80 Q 150 110 120 110 L 55 110 Q 25 110 25 80 L 25 75 L 3 60 L 25 45 L 25 40 Q 25 10 55 10 Z" fill="none" stroke="' + color + '" stroke-width="5" stroke-linejoin="round"/><text x="87" y="77" font-family="Arial, sans-serif" text-anchor="middle" dominant-baseline="middle" font-size="50" font-weight="bold" fill="' + color + '">' + displayText + '</text></svg>';
        }
    } else {
        svg = isValidSvg ? customSvg : '<svg width="1000" height="909" xmlns="http://www.w3.org/2000/svg"><path d="M80,80 h840 a60,60 0 0 1 60,60 v580 a60,60 0 0 1 -60,60 h-620 l-140,90 v-90 h-80 a60,60 0 0 1 -60,-60 v-580 a60,60 0 0 1 60,-60 z" fill="none" stroke="' + color + '" stroke-width="16" stroke-linejoin="round"/><text x="500" y="450" font-family="Arial, sans-serif" text-anchor="middle" font-size="360" fill="' + color + '" dy="0.3em">' + displayText + '</text></svg>';
    }

    var encodedSvg = java.base64Encode(svg);

    const jsFunction = {
        'jj': 'showJJCmt',
        'qm': 'showQmCmt',
        'qq': 'showQQCmt',
        'fq': 'showCmt'
    }[sourceType] || 'showCmt';

    const baseData = `data:image/svg+xml;base64,${encodedSvg},{'${isModifiedVersion ? 'click' : 'js'}':'${jsFunction}("${bid}","${cid}","${para}","${date}")','style':'${imageStyle}'}`;

    if (sourceType == 'qq' && para == 0) return baseData;
    return deviceType.call(this) ? baseData : `<img src="${baseData}">`;
}

function checkClickRateLimit(lastCallKey) {
    let {
        cache
    } = this;
    let lastCallTime = cache.getFromMemory(lastCallKey) || 0;
    let currentTime = Date.now();
    if (currentTime - lastCallTime < 1000) {
        return false;
    }
    cache.putMemory(lastCallKey, currentTime);
    return true;
}

function handleCommentClick(sourceType, bid, cid, para, date, cacheKey) {
    let {
        cache
    } = this;
    let isModifiedVersion = checkEnv.call(this);
    let isQingRead = isQRead.call(this);

    if (!isModifiedVersion && !isQingRead) {
        let mname = cacheKey;
        let load = (cache.getFromMemory(mname) ?? "-").split("-");
        if (load[0] != "1" || load[1] != date) {
            cache.putMemory(mname, "1-" + date);
            return;
        }
        let lastCallKey = `last_call_${sourceType}_${bid}_${cid}_${para}`;
        if (!checkClickRateLimit.call(this, lastCallKey)) {
            return;
        }
    }

    let commentUrl = buildCommentUrl.call(this, sourceType, bid, cid, para);
    let title = isModifiedVersion ? getCommentSourceName(sourceType) + "段评" : (cache.getFromMemory(cacheKey + "-text") ?? getCommentSourceName(sourceType) + "段评");
    startCommentBrowser.call(this, commentUrl, title);
}

function getComments(content, bid, cid, sourceType = 'fq', contentMd5 = null, extraParams = {}) {
    let {
        java,
        cache,
        source
    } = this;
    let host = getServerHost.call(this);
    try {
        let lines = String(content)
            .replace(new RegExp('(<img[^>]*?>)\n', 'g'), "$1")
            .split("\n")
            .filter(line => line.trim());

        let isModifiedVersion = checkEnv.call(this);
        let isQingRead = isQRead.call(this);

        if (sourceType == 'jj') {
            let apiUrl = `${host}/proxy_jjidea?bid=${bid}&cid=${cid}`;

            if (extraParams.bookid && extraParams.chapterid) {
                apiUrl += `&bookid=${extraParams.bookid}&chapterid=${extraParams.chapterid}`;
            }

            let token = JJtoken.call(this);
            if (token) {
                apiUrl += `&token=${token}`;
            }

            let response = java.ajax(apiUrl);
            let data = JSON.parse(response).data;

            data.forEach((item) => {
                let para = item.paragraph_id;
                let count = item.comment_total;

                let paraNum = parseInt(para);
                if (paraNum <= 0 || paraNum > lines.length) {
                    return;
                }

                let adjustedPara = paraNum - 1;

                if (!isModifiedVersion && !isQingRead) {
                    cache.putMemory(`jj-${bid}-${cid}-${para}-text`, lines[adjustedPara]);
                }

                let color = getCommentIconColor.call(this);
                let commentTag = createSvg.call(this, count, color, bid, cid, para, sourceType);
                if (deviceType.call(this)) {
                    lines[adjustedPara] += `<img src="${commentTag}">`;
                } else {
                    lines[adjustedPara] += commentTag;
                }
            });
        } else if (sourceType == 'qm') {
            if (!contentMd5) return wrapContentForIOS.call(this, content);

            let apiUrl = `${host}/proxy_qmidea?action=paragraph_bubbles&book_id=${bid}&item_id=${cid}&content_md5=${contentMd5}`;
            let response = java.ajax(apiUrl);
            let data = JSON.parse(response).data;

            if (data.chapters && data.chapters.length > 0) {
                let chapterData = data.chapters[0];
                if (chapterData.bubbles) {
                    chapterData.bubbles.forEach((bubble, bubbleIndex) => {
                        let paraMd5 = bubble.p;
                        let count = parseInt(bubble.c) || 0;

                        if (count > 0 && bubbleIndex < lines.length) {
                            let paraIndex = bubbleIndex;

                            if (!isModifiedVersion && !isQingRead) {
                                cache.putMemory(`qm-${bid}-${cid}-${paraMd5}-text`, lines[paraIndex]);
                            }

                            let color = getCommentIconColor.call(this);
                            let commentTag = createSvg.call(this, count, color, bid, cid, paraMd5, sourceType);
                            if (deviceType.call(this)) {
                                lines[paraIndex] += `<img src="${commentTag}">`;
                            } else {
                                lines[paraIndex] += commentTag;
                            }
                        }
                    });
                }
            }
        } else if (sourceType == 'qq') {
            let apiUrl = `${host}/proxy_qqidea?bid=${bid}&cid=${cid}`;
            let response = java.ajax(apiUrl);
            let data = JSON.parse(response);

            let hasTitleComment = false;
            let titleCommentData = null;

            if (data.noteCount && data.noteCount.length > 0) {
                let noteData = data.noteCount[0];
                if (noteData.data && noteData.data.length > 0) {
                    noteData.data.forEach((item) => {
                        let paraOffset = item.paragraphOffset;
                        let count = item.count || 0;

                        if (count > 0) {
                            if (paraOffset == 0) {
                                hasTitleComment = true;
                                titleCommentData = item;
                            } else {
                                let lineIndex = paraOffset - 1;

                                if (lineIndex >= 0 && lineIndex < lines.length) {
                                    if (!isModifiedVersion && !isQingRead) {
                                        cache.putMemory(`qq-${bid}-${cid}-${paraOffset}-text`, lines[lineIndex]);
                                    }

                                    let color = getCommentIconColor.call(this);
                                    let commentTag = createSvg.call(this, count, color, bid, cid, paraOffset, sourceType);
                                    if (deviceType.call(this)) {
                                        lines[lineIndex] += `<img src="${commentTag}">`;
                                    } else {
                                        lines[lineIndex] += commentTag;
                                    }
                                }
                            }
                        }
                    });
                }
            }

            if (hasTitleComment && titleCommentData) {
                let color = getCommentIconColor.call(this);
                let titleBubble = createSvg.call(this, titleCommentData.count, color, bid, cid, 0, sourceType);
                cache.put(bid + "_" + cid, titleBubble);
            }
        } else {
            let apiUrl = `${host}/proxy_idea?item_id=${cid}`;
            let comments = java.ajax(apiUrl);
            let raw = JSON.parse(comments).data.data;

            Object.keys(raw).forEach((x) => {
                let lineIndex = parseInt(x);

                if (lineIndex >= lines.length || lineIndex < 0) {
                    return;
                }

                let lineContent = lines[lineIndex];

                let textOnly = String(lineContent)
                    .replace(new RegExp('<[^>]*>', 'g'), '')
                    .replace(/&nbsp;/g, ' ')
                    .trim();

                if (!textOnly) {
                    return;
                }

                if (!isModifiedVersion && !isQingRead) {
                    cache.putMemory(`fq-${bid}-${cid}-${x}-text`, textOnly || lineContent);
                }

                let color = getCommentIconColor.call(this);
                let commentTag = createSvg.call(this, raw[x].count, color, bid, cid, x, sourceType);
                if (deviceType.call(this)) {
                    lines[lineIndex] += `<img src="${commentTag}">`;
                } else {
                    lines[lineIndex] += commentTag;
                }
            });
        }

        let result = lines.join("\n");
        return wrapContentForIOS.call(this, result);
    } catch (e) {
        return wrapContentForIOS.call(this, content);
    }
}

